mapper.sql:
FROM vehicle v
JOIN model m ON m.model_id = v.model_id
JOIN brand b ON b.brand_id = m.brand_id


        AND v.vehicle_vin LIKE CONCAT(#{query.vehicleVin}, '%')


        AND b.brand_id = #{query.brandId}


        AND m.model_id = #{query.modelId}


        AND v.current_status = #{query.currentStatus}


        AND v.color = #{query.color}


        AND v.inventory_in_date >= #{query.inventoryInDateStart}


        AND v.inventory_in_date <= #{query.inventoryInDateEnd}


        AND v.manufacture_date >= #{query.manufactureDateStart}


        AND v.manufacture_date <= #{query.manufactureDateEnd}
